components.codeTemplate:
Canvas { context, size in /* draw bars */ }
    .accessibilityLabel("Weekly lines of code")
    .accessibilityChildren {
        {children}
    }

@ScaledMetric(relativeTo: {relativeTo}) private var iconSize: CGFloat = {wrappedValue}

var body: some View {
    Image(systemName: "bell")
        .frame(width: iconSize, height: iconSize)
}

CustomSlider(value: $value)
    .accessibilityValue("\(Int(value)) percent")
    .accessibilityAdjustableAction { direction in
        switch direction {
        case .increment: value = min(value + 1, 100)
        case .decrement: value = max(value - 1, 0)
        @unknown default: break
        }
    }

CarouselView(index: $index)
    .accessibilityScrollAction { edge in
        if edge == .trailing { index += 1 }
        else if edge == .leading { index -= 1 }
    }

ScrollView {
    LazyVStack { ForEach(messages) { MessageView($0) } }
}
.accessibilityElement(children: .contain)
.accessibilityRotor({rotorLabel}, entries: {entries}, entryLabel: {entryLabel})

@AccessibilityFocusState private var focus: Field?

var body: some View {
    TextField("Email", text: $email)
        .accessibilityFocused($focus, equals: .{equalsValue})
        .onChange(of: hasError) { _, error in if error { focus = .{equalsValue} } }
}

@Environment(\.accessibilityReduceMotion) private var reduceMotion

var body: some View {
    CardView()
        .animation(reduceMotion ? nil : .spring, value: isExpanded)
}

@Environment(\.accessibilityReduceTransparency) private var reduceTransparency

var body: some View {
    content
        .background(reduceTransparency ? AnyShapeStyle(.background) : AnyShapeStyle(.ultraThinMaterial))
}

@Environment(\.accessibilityDifferentiateWithoutColor) private var differentiate

var body: some View {
    HStack {
        if differentiate { Image(systemName: isValid ? "checkmark.circle" : "xmark.circle") }
        Text(status)
    }
    .foregroundStyle(isValid ? .green : .red)
}

@Environment(\.colorSchemeContrast) private var contrast

var body: some View {
    Text("Label")
        .foregroundStyle(contrast == .increased ? .primary : .secondary)
}

@Environment(\.accessibilityShowButtonShapes) private var showShapes

var body: some View {
    Button("Skip") { }
        .background(showShapes ? AnyShapeStyle(.quaternary) : AnyShapeStyle(.clear), in: .capsule)
}

EditorView()
    .accessibilityQuickAction(style: .{style}, isActive: {isActive}) {
        Button("Format") { format() }
        Button("Share") { share() }
    }

@Namespace private var pairNS

var body: some View {
    Grid {
        GridRow {
            Text("Price").accessibilityLabeledPair(role: .label, id: {id}, in: pairNS)
            Text("$9.99").accessibilityLabeledPair(role: .content, id: {id}, in: pairNS)
        }
    }
}

@Namespace private var rotorNS

ForEach(messages) { message in
    MessageView(message)
        .accessibilityRotorEntry(id: message.id, in: rotorNS)
}

@Namespace private var linkNS

var body: some View {
    HStack {
        ListColumn().accessibilityLinkedGroup(id: selectedID, in: linkNS)
        DetailColumn().accessibilityLinkedGroup(id: selectedID, in: linkNS)
    }
}
